CREATE VIEW `dwd_interaction_user_ladder_task_record_view` (`dt` COMMENT "createtime分区", `product_id` COMMENT "createtime分区", `id` COMMENT "主键id", `pid` COMMENT "用户id", `act_id` COMMENT "活动id", `ladder_id` COMMENT "阶梯任务id", `read_time` COMMENT "活动阅读时长(秒)", `coin_consume` COMMENT "活动阅币消费", `recharge_money` COMMENT "活动充值金额", `isunlock_paid_reward` COMMENT "是否解锁付费奖励 0：未解锁 1：已解锁", `freenum_record` COMMENT "免费档位记录", `paynum_record` COMMENT "付费档位记录", `create_time` COMMENT "创建时间", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
COMMENT "海外阅读-用户阶梯任务记录" AS SELECT `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`dt`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`product_id`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`id`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`pid`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`actid` AS `act_id`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`ladderid` AS `ladder_id`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`readtime` AS `read_time`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`coinconsume` AS `coin_consume`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`rechargemoney` AS `recharge_money`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`isunlockpaidreward` AS `isunlock_paid_reward`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`freenumrecord` AS `freenum_record`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`paynumrecord` AS `paynum_record`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`createtime` AS `create_time`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`sr_createtime`, `ods`.`ods_tidb_readernovel_userladdertaskrecord`.`sr_updatetime`
FROM `ods`.`ods_tidb_readernovel_userladdertaskrecord`;
